def is_balanced(s: str) -> bool:
    """
    Проверяет, сбалансированы ли скобки в строке.

    Функция игнорирует все символы, кроме '()', '[]' и '{}'.
    Возвращает True, если каждая открывающая скобка имеет соответствующую
    закрывающую скобку правильного типа и в правильном порядке.
    В противном случае возвращает False.
    """
    stack = []
    matching_bracket = {')': '(', ']': '[', '}': '{'}

    for char in s:
        if char in '([{':
            stack.append(char)
        elif char in ')]}':
            if not stack or stack[-1] != matching_bracket[char]:
                return False
            stack.pop()

    return len(stack) == 0

